class TokenRefreshResponseSerializer(serializers.Serializer):
    access  = serializers.CharField()
    refresh = serializers.CharField()


# ─── Password Reset ───────────────────────────────────────────────────────────

class PasswordResetRequestSerializer(serializers.Serializer):
    email = serializers.EmailField()

    def validate_email(self, value):
        return value.lower().strip()


class PasswordResetConfirmSerializer(serializers.Serializer):
    token        = serializers.CharField()
    new_password = serializers.CharField(write_only=True, min_length=8)

    def validate_new_password(self, value):
        strength = _password_strength(value)
        if strength["level"] == "weak":
            raise serializers.ValidationError(
                "Password is too weak. Use at least 8 characters with uppercase, lowercase, and digits."
            )
        return value


# ─── Password Strength Check (standalone endpoint) ───────────────────────────

class PasswordStrengthSerializer(serializers.Serializer):
    password = serializers.CharField(write_only=True)

    def validate(self, attrs):
        attrs["strength"] = _password_strength(attrs["password"])
        return attrs


# ─── User Profile ─────────────────────────────────────────────────────────────

class UserMiniSerializer(serializers.ModelSerializer):
    """Compact user representation used inside auth responses and friend lists."""

    class Meta:
        model = User
        fields = [
            "id", "email", "full_name", "display_name", "avatar_url",
            "country_code", "timezone", "language_preference",
            "voice_trained", "profile_complete", "language_selected",
            "is_online", "last_seen", "auth_provider", "created_at",
        ]
        read_only_fields = fields


class UserProfileSerializer(serializers.ModelSerializer):
    """Full profile — returned for /api/v1/users/me/"""

    class Meta:
        model = User
        fields = [
            "id", "email", "full_name", "display_name", "avatar_url",
            "bio", "date_of_birth", "country_code", "timezone",
            "language_preference", "voice_trained", "profile_complete",
            "language_selected", "is_online", "last_seen",
            "last_seen_visibility", "show_read_receipts", "show_online_status",
            "auth_provider", "is_verified", "created_at", "updated_at",
        ]
        read_only_fields = [
            "id", "email", "supabase_uid", "auth_provider",
            "voice_trained", "is_verified", "created_at", "updated_at",
        ]

    def validate_display_name(self, value):
        value = value.strip()
        if len(value) < 2 or len(value) > 60:
            raise serializers.ValidationError("Display name must be 2–60 characters.")
        return value

    def validate_bio(self, value):
        if len(value) > 160:
            raise serializers.ValidationError("Bio cannot exceed 160 characters.")
        return value.strip()

    def validate_language_preference(self, value):
        if value not in settings.YAAP_SUPPORTED_LANGUAGES:
            raise serializers.ValidationError(
                f"Unsupported language. Choose from: {', '.join(settings.YAAP_SUPPORTED_LANGUAGES)}"
            )
        return value

    def validate_country_code(self, value):
        if value and len(value) != 2:
            raise serializers.ValidationError("Country code must be a 2-letter ISO code (e.g. 'PK').")
        return value.upper()


class UserPublicProfileSerializer(serializers.ModelSerializer):
    """
    Public profile — what OTHER users see.
    Respects privacy settings: last_seen and online status may be hidden.
    """
    last_seen   = serializers.SerializerMethodField()
    is_online   = serializers.SerializerMethodField()

    class Meta:
        model = User
        fields = [
            "id", "display_name", "avatar_url", "bio",
            "country_code", "timezone", "language_preference",
            "is_online", "last_seen", "created_at",
        ]

    def get_last_seen(self, obj):
        requesting_user = self.context.get("request").user
        vis = obj.last_seen_visibility
        if vis == User.LastSeenVisibility.NOBODY:
            return None
        if vis == User.LastSeenVisibility.FRIENDS:
            from apps.friendships.models import Friendship
            if not Friendship.objects.are_friends(requesting_user, obj):
                return None
        return obj.last_seen

    def get_is_online(self, obj):
        if not obj.show_online_status:
            return None
        return obj.is_online


class UpdateLanguageSerializer(serializers.Serializer):
    language_preference = serializers.ChoiceField(
        choices=settings.YAAP_SUPPORTED_LANGUAGES
    )


class UserSearchSerializer(serializers.ModelSerializer):
    """Result card for /api/v1/users/search/"""
    friendship_status = serializers.SerializerMethodField()
    mutual_friends    = serializers.SerializerMethodField()

    class Meta:
        model = User
        fields = [
            "id", "display_name", "avatar_url", "country_code",
            "language_preference", "is_online", "friendship_status", "mutual_friends",
        ]

    def get_friendship_status(self, obj):
        from apps.friendships.models import Friendship, FriendRequest
        requesting_user = self.context["request"].user
        if Friendship.objects.are_friends(requesting_user, obj):
            return "friends"
        req = FriendRequest.objects.filter(
            from_user=requesting_user, to_user=obj, status=FriendRequest.Status.PENDING
        ).first()
        if req:
            return "requested"
        return "none"

    def get_mutual_friends(self, obj):
        from apps.friendships.models import Friendship
        requesting_user = self.context["request"].user
        return Friendship.objects.mutual_friends_count(requesting_user, obj)

"""
YAAP Auth Views
All three authentication flows:
  1. Email + Password  (signup / login)
  2. Email OTP         (request code / verify code)
  3. Google OAuth      (verify ID token from Android SDK)
"""

import logging
import random
import string
from datetime import timedelta

import httpx
from django.conf import settings
from django.contrib.auth import get_user_model
from django.utils import timezone
from drf_spectacular.utils import extend_schema, OpenApiResponse
from rest_framework import status
from rest_framework.permissions import AllowAny, IsAuthenticated
from rest_framework.response import Response
from rest_framework.views import APIView
from rest_framework_simplejwt.exceptions import TokenError
from rest_framework_simplejwt.tokens import RefreshToken
from rest_framework_simplejwt.views import TokenRefreshView

from apps.accounts.models import EmailOTP
from apps.accounts.serializers import (
    GoogleAuthSerializer,
    LoginSerializer,
    LogoutSerializer,
    OTPRequestSerializer,
    OTPVerifySerializer,
    PasswordResetConfirmSerializer,
    PasswordResetRequestSerializer,
    PasswordStrengthSerializer,
    SignupSerializer,
    UserMiniSerializer,
    _make_tokens,
)



from services.supabase_client import get_supabase_admin_client
from services.email_service import send_otp_email, send_password_reset_email

logger = logging.getLogger(__name__)
User = get_user_model()


def _success(data: dict, status_code=status.HTTP_200_OK) -> Response:
    return Response({"success": True, "data": data}, status=status_code)


# ─── Email + Password Signup ──────────────────────────────────────────────────

class SignupView(APIView):
    permission_classes = [AllowAny]

    @extend_schema(
        request=SignupSerializer,
        responses={201: OpenApiResponse(description="User created, tokens returned")},
        summary="Register with email and password",
        tags=["Authentication"],
    )
    def post(self, request):
        serializer = SignupSerializer(data=request.data)
        serializer.is_valid(raise_exception=True)

        user = serializer.save()

        # Also register in Supabase Auth so Supabase RLS policies work
        try:
            supabase = get_supabase_admin_client()
            sb_user = supabase.auth.admin.create_user({
                "email": user.email,
                "password": request.data.get("password"),
                "email_confirm": True,
                "user_metadata": {"yaap_user_id": str(user.id)},
            })
            user.supabase_uid = sb_user.user.id
            user.is_verified  = True
            user.save(update_fields=["supabase_uid", "is_verified"])
        except Exception as e:
            logger.error("Supabase user creation failed for %s: %s", user.email, e)
            # Non-fatal — Django auth still works; Supabase sync can be retried

        tokens = _make_tokens(user)
        return _success(
            {
                "user":             UserMiniSerializer(user).data,
                "tokens":           tokens,
                "password_strength": serializer.validated_data.get("password_strength"),
                "next_step":        "personal_details",
            },
            status.HTTP_201_CREATED,
        )


# ─── Email + Password Login ───────────────────────────────────────────────────

class LoginView(APIView):
    permission_classes = [AllowAny]

    @extend_schema(
        request=LoginSerializer,
        summary="Login with email and password",
        tags=["Authentication"],
    )
    def post(self, request):
        serializer = LoginSerializer(data=request.data, context={"request": request})
        serializer.is_valid(raise_exception=True)

        user   = serializer.validated_data["user"]
        tokens = _make_tokens(user)

        return _success({
            "user":      UserMiniSerializer(user).data,
            "tokens":    tokens,
            "next_step": _resolve_next_step(user),
        })


# ─── Email OTP — Request ──────────────────────────────────────────────────────

class OTPRequestView(APIView):
    permission_classes = [AllowAny]

    @extend_schema(
        request=OTPRequestSerializer,
        summary="Request a 6-digit OTP for passwordless login",
        tags=["Authentication"],
    )
    def post(self, request):
        serializer = OTPRequestSerializer(data=request.data)
        serializer.is_valid(raise_exception=True)

        email = serializer.validated_data["email"]

        # Invalidate all previous OTPs for this email
        EmailOTP.objects.filter(email=email, is_used=False).update(is_used=True)

        # Generate new OTP
        code = "".join(random.choices(string.digits, k=6))
        otp  = EmailOTP.objects.create(
            email      = email,
            code       = code,
            expires_at = timezone.now() + timedelta(minutes=settings.OTP_EXPIRY_MINUTES),
        )

        # Send email (non-blocking via Celery)
        try:
            send_otp_email.delay(email, code)
        except Exception as e:
            logger.error("Failed to enqueue OTP email for %s: %s", email, e)
            # Fall back to synchronous send
            send_otp_email(email, code)

        return _success({
            "message":      f"A 6-digit code has been sent to {email}.",
            "expires_in":   settings.OTP_EXPIRY_MINUTES * 60,  # seconds
        })


# ─── Email OTP — Verify ───────────────────────────────────────────────────────

class OTPVerifyView(APIView):
    permission_classes = [AllowAny]

    @extend_schema(
        request=OTPVerifySerializer,
        summary="Verify OTP code — creates account if new user",
        tags=["Authentication"],
    )
    def post(self, request):
        serializer = OTPVerifySerializer(data=request.data)
        serializer.is_valid(raise_exception=True)

        email = serializer.validated_data["email"]
        otp   = serializer.validated_data["otp"]

        # Mark OTP as used
        otp.is_used = True
        otp.save(update_fields=["is_used"])

        # Get or create user
        user, created = User.objects.get_or_create(
            email=email,
            defaults={
                "full_name":     email.split("@")[0],
                "auth_provider": User.AuthProvider.EMAIL_OTP,
                "is_verified":   True,
            },
        )
        if created:
            user.set_unusable_password()
            user.save()

            # Create in Supabase
            try:
                supabase = get_supabase_admin_client()
                sb_user  = supabase.auth.admin.create_user({
                    "email": email,
                    "email_confirm": True,
                    "user_metadata": {"yaap_user_id": str(user.id)},
                })
                user.supabase_uid = sb_user.user.id
                user.save(update_fields=["supabase_uid"])
            except Exception as e:
                logger.error("Supabase OTP user creation failed: %s", e)

        elif not user.is_verified:
            user.is_verified = True
            user.save(update_fields=["is_verified"])

        tokens = _make_tokens(user)
        return _success({
            "user":      UserMiniSerializer(user).data,
            "tokens":    tokens,
            "is_new":    created,
            "next_step": _resolve_next_step(user),
        })


# ─── Google OAuth ─────────────────────────────────────────────────────────────

class GoogleAuthView(APIView):
    permission_classes = [AllowAny]

    @extend_schema(
        request=GoogleAuthSerializer,
        summary="Authenticate with Google ID token (from Android SDK)",
        tags=["Authentication"],
    )
    def post(self, request):
        serializer = GoogleAuthSerializer(data=request.data)
        serializer.is_valid(raise_exception=True)

        id_token = serializer.validated_data["id_token"]

        # Verify Google ID token
        google_payload = self._verify_google_token(id_token)
        if not google_payload:
            return Response(
                {"success": False, "error": {"code": "INVALID_TOKEN", "message": "Invalid Google ID token."}},
                status=status.HTTP_401_UNAUTHORIZED,
            )

        email       = google_payload.get("email", "").lower().strip()
        full_name   = google_payload.get("name", "")
        avatar_url  = google_payload.get("picture", "")
        google_sub  = google_payload.get("sub", "")

        if not email:
            return Response(
                {"success": False, "error": {"code": "NO_EMAIL", "message": "Google account has no email."}},
                status=status.HTTP_400_BAD_REQUEST,
            )

        user, created = User.objects.get_or_create(
            email=email,
            defaults={
                "full_name":     full_name,
                "display_name":  full_name,
                "avatar_url":    avatar_url,
                "auth_provider": User.AuthProvider.GOOGLE,
                "is_verified":   True,
            },
        )

        if created:
            try:
                supabase = get_supabase_admin_client()
                sb_user  = supabase.auth.admin.create_user({
                    "email": email,
                    "email_confirm": True,
                    "user_metadata": {
                        "yaap_user_id": str(user.id),
                        "google_sub":   google_sub,
                    },
                })
                user.supabase_uid = sb_user.user.id
                user.save(update_fields=["supabase_uid"])
            except Exception as e:
                logger.error("Supabase Google user creation failed: %s", e)
        else:
            # Update avatar if changed
            if avatar_url and user.avatar_url != avatar_url:
                user.avatar_url = avatar_url
                user.save(update_fields=["avatar_url"])

        tokens = _make_tokens(user)
        return _success({
            "user":      UserMiniSerializer(user).data,
            "tokens":    tokens,
            "is_new":    created,
            "next_step": _resolve_next_step(user),
        }, status.HTTP_201_CREATED if created else status.HTTP_200_OK)

    @staticmethod
    def _verify_google_token(id_token: str) -> dict | None:
        """Verify Google ID token via Google's tokeninfo endpoint."""
        try:
            response = httpx.get(
                "https://oauth2.googleapis.com/tokeninfo",
                params={"id_token": id_token},
                timeout=5.0,
            )
            if response.status_code != 200:
                logger.warning("Google token verification failed: %s", response.text)
                return None

            payload = response.json()

            # Verify audience matches our client ID
            if payload.get("aud") != settings.GOOGLE_CLIENT_ID:
                logger.warning("Google token aud mismatch: %s", payload.get("aud"))
                return None

            return payload
        except Exception as e:
            logger.error("Google token verification error: %s", e)
            return None


# ─── Logout ───────────────────────────────────────────────────────────────────

class LogoutView(APIView):
    permission_classes = [IsAuthenticated]

    @extend_schema(summary="Logout", tags=["Authentication"])
    def post(self, request):
        refresh_token = request.data.get("refresh")

        # Try to blacklist refresh token only if client sent it.
        if refresh_token:
            try:
                token = RefreshToken(refresh_token)
                token.blacklist()
            except TokenError as e:
                logger.warning("Logout with invalid refresh token: %s", e)
            except Exception as e:
                logger.warning("Unexpected logout blacklist error: %s", e)

        # Always try to mark user offline, but don't let this break logout.
        try:
            request.user.mark_offline()
        except Exception as e:
            logger.warning("Failed to mark user offline during logout: %s", e)

        return _success({"message": "Logged out successfully."})


