class BlockSerializer(serializers.ModelSerializer):
    blocked_user = UserMiniSerializer(source="blocked", read_only=True)

    class Meta:
        model = Block
        fields = ["id", "blocked_user", "created_at"]
        read_only_fields = fields


class BlockUserSerializer(serializers.Serializer):
    user_id = serializers.UUIDField()

    def validate_user_id(self, value):
        from django.contrib.auth import get_user_model
        User = get_user_model()
        requesting_user = self.context["request"].user

        if str(value) == str(requesting_user.id):
            raise serializers.ValidationError("You cannot block yourself.")
        if not User.objects.filter(id=value, is_active=True).exists():
            raise serializers.ValidationError("User not found.")
        if Block.objects.filter(blocker=requesting_user, blocked_id=value).exists():
            raise serializers.ValidationError("You have already blocked this user.")
        return value


# ─── UserDevice (FCM Token) ───────────────────────────────────────────────────

class RegisterDeviceSerializer(serializers.ModelSerializer):
    device_name = serializers.CharField(required=False, allow_blank=True, default="")
    fcm_token = serializers.CharField(required=False, allow_blank=False)

    class Meta:
        model = UserDevice
        fields = ["fcm_token", "device_name"]

    def validate(self, attrs):
        raw = self.initial_data or {}

        if not attrs.get("fcm_token"):
            attrs["fcm_token"] = (
                raw.get("fcm_token")
                or raw.get("token")
                or raw.get("device_token")
                or raw.get("registration_token")
            )

        if not attrs.get("device_name"):
            attrs["device_name"] = (
                raw.get("device_name")
                or raw.get("platform")
                or raw.get("device")
                or ""
            )

        if not attrs.get("fcm_token"):
            raise serializers.ValidationError({"fcm_token": "FCM token is required."})

        return attrs

    def create(self, validated_data):
        user = self.context["request"].user
        device, _ = UserDevice.objects.update_or_create(
            fcm_token=validated_data["fcm_token"],
            defaults={
                "user": user,
                "device_name": validated_data.get("device_name", ""),
            },
        )
        return device

"""
Friendships Views
All endpoints for friend requests, friends list, block/unblock, and FCM device registration.

Endpoint map (all under /api/v1/friends/):
  GET    /                          — list accepted friends
  DELETE /{friendship_id}/          — unfriend

  POST   /request/                  — send a friend request
  GET    /requests/received/        — incoming pending requests
  GET    /requests/sent/            — outgoing pending requests
  POST   /requests/{id}/accept/     — accept an incoming request
  POST   /requests/{id}/decline/    — decline an incoming request
  DELETE /requests/{id}/            — cancel an outgoing request

  POST   /block/                    — block a user
  DELETE /block/{user_id}/          — unblock a user
  GET    /blocked/                  — list blocked users

  POST   /devices/                  — register FCM device token
  DELETE /devices/{token}/          — remove FCM token on logout
"""

