"""Voice App Serializers"""

from django.conf import settings
from rest_framework import serializers
from .models import VoiceSample, VoiceTrainingJob, VoiceSentence


class VoiceSentenceSerializer(serializers.ModelSerializer):
    class Meta:
        model  = VoiceSentence
        fields = ["id", "language", "sentence", "position"]
        read_only_fields = fields


class VoiceSampleUploadSerializer(serializers.Serializer):
    """Validates an incoming voice sample upload."""
    audio_file   = serializers.FileField()
    sample_index = serializers.IntegerField(min_value=1, max_value=settings.YAAP_MAX_VOICE_SAMPLES)
    sentence_id  = serializers.UUIDField(required=False, allow_null=True)

    def validate_audio_file(self, value):
        allowed_types = {"audio/wav", "audio/wave", "audio/x-wav", "audio/webm", "audio/ogg", "audio/mp4", "audio/mpeg"}
        if value.content_type not in allowed_types:
            raise serializers.ValidationError(
                f"Unsupported audio format '{value.content_type}'. Upload WAV, WebM, OGG, or MP4."
            )
        max_bytes = 50 * 1024 * 1024  # 50 MB
        if value.size > max_bytes:
            raise serializers.ValidationError("Audio file exceeds 50 MB limit.")
        return value


class VoiceSampleSerializer(serializers.ModelSerializer):
    sentence = VoiceSentenceSerializer(read_only=True)

    class Meta:
        model  = VoiceSample
        fields = ["id", "sample_index", "sentence", "duration_seconds",
                  "file_size_bytes", "noise_floor_db", "uploaded_at"]
        read_only_fields = fields


class VoiceTrainingJobSerializer(serializers.ModelSerializer):
    duration_seconds = serializers.SerializerMethodField()
    progress_percent = serializers.SerializerMethodField()

    class Meta:
        model  = VoiceTrainingJob
        fields = ["id", "status", "samples_count", "error_message",
                  "started_at", "completed_at", "created_at",
                  "duration_seconds", "progress_percent"]
        read_only_fields = fields

    def get_duration_seconds(self, obj):
        return obj.duration_seconds

    def get_progress_percent(self, obj):
        mapping = {
            VoiceTrainingJob.Status.PENDING:    10,
            VoiceTrainingJob.Status.PROCESSING: 50,
            VoiceTrainingJob.Status.COMPLETED:  100,
            VoiceTrainingJob.Status.FAILED:     0,
        }
        return mapping.get(obj.status, 0)


class VoiceStatusSerializer(serializers.Serializer):
    """Full training status response returned to the Kotlin app."""
    voice_trained        = serializers.BooleanField()
    samples_uploaded     = serializers.IntegerField()
    samples_required     = serializers.IntegerField()
    all_samples_uploaded = serializers.BooleanField()
    active_job           = VoiceTrainingJobSerializer(allow_null=True)
    samples              = VoiceSampleSerializer(many=True)

"""
Voice App Views
"""
import logging
from django.conf import settings
from django.db import transaction
from drf_spectacular.utils import extend_schema
from rest_framework import status
from rest_framework.parsers import MultiPartParser, FormParser
from rest_framework.permissions import IsAuthenticated
from rest_framework.response import Response
from rest_framework.views import APIView
from .models import VoiceSample, VoiceSentence, VoiceTrainingJob
from .serializers import (
    VoiceSampleSerializer, VoiceSampleUploadSerializer,
    VoiceSentenceSerializer, VoiceTrainingJobSerializer,
)

logger = logging.getLogger(__name__)
def _ok(d, sc=status.HTTP_200_OK): return Response({"success": True, "data": d}, status=sc)
def _err(c, m, sc=status.HTTP_400_BAD_REQUEST): return Response({"success": False, "error": {"code": c, "message": m}}, status=sc)


class VoiceSentencesView(APIView):
    permission_classes = [IsAuthenticated]
    def get(self, request):
        lang = request.user.language_preference
        qs   = VoiceSentence.objects.for_language(lang)
        if not qs.exists():
            lang = "en"
            qs   = VoiceSentence.objects.for_language(lang)
        if not qs.exists():
            return _err("NO_SENTENCES", "Training sentences not found.", status.HTTP_503_SERVICE_UNAVAILABLE)
        return _ok({"language": lang, "language_name": settings.YAAP_LANGUAGE_NAMES.get(lang, lang),
                    "sentences": VoiceSentenceSerializer(qs, many=True).data, "total_required": settings.YAAP_MAX_VOICE_SAMPLES})


class VoiceSampleUploadView(APIView):
    permission_classes = [IsAuthenticated]
    parser_classes = [MultiPartParser, FormParser]
    def post(self, request):
        s = VoiceSampleUploadSerializer(data=request.data)
        s.is_valid(raise_exception=True)
        audio_file   = s.validated_data["audio_file"]
        sample_index = s.validated_data["sample_index"]
        sentence_id  = s.validated_data.get("sentence_id")
        from services.audio_processing import validate_and_process_wav
        raw_bytes = audio_file.read()
        result    = validate_and_process_wav(raw_bytes, filename=audio_file.name)
        if not result["ok"]:
            return _err("INVALID_AUDIO", result["error"])
        storage_path = f"{request.user.id}/sample_{sample_index}.wav"
        try:
            from services.supabase_client import upload_file
            upload_file(settings.SUPABASE_STORAGE_BUCKET_VOICE_SAMPLES, storage_path, result["processed_bytes"], "audio/wav")
        except Exception as e:
            logger.error("Upload failed: %s", e)
            return _err("UPLOAD_FAILED", "Storage error.", status.HTTP_500_INTERNAL_SERVER_ERROR)
        sentence = None
        if sentence_id:
            try: sentence = VoiceSentence.objects.get(id=sentence_id)
            except VoiceSentence.DoesNotExist: pass
        sample, created = VoiceSample.objects.update_or_create(
            user=request.user, sample_index=sample_index,
            defaults={"storage_path": storage_path, "sentence": sentence,
                      "duration_seconds": result["duration"], "file_size_bytes": len(result["processed_bytes"]),
                      "noise_floor_db": result["noise_floor_db"]},
        )
        uploaded_count = VoiceSample.objects.filter(user=request.user).count()
        return _ok({"sample": VoiceSampleSerializer(sample).data, "samples_uploaded": uploaded_count,
                    "samples_required": settings.YAAP_MAX_VOICE_SAMPLES,
                    "all_uploaded": uploaded_count >= settings.YAAP_MAX_VOICE_SAMPLES,
                    "noise_warning": result["noise_floor_db"] > -40.0,
                    "noise_floor_db": result["noise_floor_db"]},
                   status.HTTP_201_CREATED if created else status.HTTP_200_OK)


class VoiceSampleDeleteView(APIView):
    permission_classes = [IsAuthenticated]
    def delete(self, request, sample_index):
        if not (1 <= sample_index <= settings.YAAP_MAX_VOICE_SAMPLES):
            return _err("INVALID_INDEX", f"sample_index must be 1-{settings.YAAP_MAX_VOICE_SAMPLES}.")
        try:
            sample = VoiceSample.objects.get(user=request.user, sample_index=sample_index)
        except VoiceSample.DoesNotExist:
            return _err("NOT_FOUND", "Sample not found.", status.HTTP_404_NOT_FOUND)
        try:
            from services.supabase_client import delete_file
            delete_file(settings.SUPABASE_STORAGE_BUCKET_VOICE_SAMPLES, sample.storage_path)
        except Exception as e:
            logger.warning("Storage delete failed: %s", e)
        sample.delete()
        return _ok({"message": f"Sample {sample_index} deleted."})


class VoiceTrainView(APIView):
    permission_classes = [IsAuthenticated]
    def post(self, request):
        user           = request.user
        uploaded_count = VoiceSample.objects.filter(user=user).count()
        if uploaded_count < settings.YAAP_MAX_VOICE_SAMPLES:
            return _err("INSUFFICIENT_SAMPLES",
                        f"Upload all {settings.YAAP_MAX_VOICE_SAMPLES} samples first. Uploaded: {uploaded_count}.")
        running = VoiceTrainingJob.objects.filter(
            user=user, status__in=[VoiceTrainingJob.Status.PENDING, VoiceTrainingJob.Status.PROCESSING]
        ).first()
        if running:
            return _ok({"job": VoiceTrainingJobSerializer(running).data, "message": "Training already in progress."})
        with transaction.atomic():
            job = VoiceTrainingJob.objects.create(user=user, samples_count=uploaded_count)
        from tasks.voice_tasks import train_voice_model
        task = train_voice_model.apply_async(args=[str(job.id)], queue="voice_training")
        job.celery_task_id = task.id
        job.save(update_fields=["celery_task_id"])
        logger.info("Voice training job: job=%s user=%s task=%s", job.id, user.id, task.id)
        return _ok({"job": VoiceTrainingJobSerializer(job).data, "message": "Training started."}, status.HTTP_202_ACCEPTED)


class VoiceStatusView(APIView):
    permission_classes = [IsAuthenticated]
    def get(self, request):
        user       = request.user
        samples    = VoiceSample.objects.filter(user=user).select_related("sentence").order_by("sample_index")
        active_job = VoiceTrainingJob.objects.filter(user=user).order_by("-created_at").first()
        uploaded   = samples.count()
        return _ok({"voice_trained": user.voice_trained, "samples_uploaded": uploaded,
                    "samples_required": settings.YAAP_MAX_VOICE_SAMPLES,
                    "all_samples_uploaded": uploaded >= settings.YAAP_MAX_VOICE_SAMPLES,
                    "active_job": VoiceTrainingJobSerializer(active_job).data if active_job else None,
                    "samples": VoiceSampleSerializer(samples, many=True).data})


class VoiceResetView(APIView):
    permission_classes = [IsAuthenticated]
    def post(self, request):
        user    = request.user
        samples = VoiceSample.objects.filter(user=user)
        from services.supabase_client import delete_file
        for s in samples:
            try: delete_file(settings.SUPABASE_STORAGE_BUCKET_VOICE_SAMPLES, s.storage_path)
            except Exception as e: logger.warning("Storage delete failed: %s", e)
        with transaction.atomic():
            samples.delete()
            VoiceTrainingJob.objects.filter(
                user=user, status__in=[VoiceTrainingJob.Status.PENDING, VoiceTrainingJob.Status.PROCESSING]
            ).update(status=VoiceTrainingJob.Status.FAILED, error_message="Reset by user.")
            user.voice_trained   = False
            user.voice_embedding = None
            user.save(update_fields=["voice_trained", "voice_embedding"])
        return _ok({"message": "Voice profile reset. Please re-record."})

"""
Chat Consumer — Phase 3 Full Implementation
ws://host/ws/chat/<conversation_id>/?token=<jwt>

Client → Server events (type field):
  send_message, typing_start, typing_stop, mark_read, delete_message, load_history

Server → Client events:
  chat.message_new, chat.message_deleted, chat.typing_start, chat.typing_stop,
  chat.read_receipt, chat.history, error
"""

import json
import logging
from channels.db import database_sync_to_async
from django.conf import settings
from channels_consumers.base_consumer import BaseConsumer

logger = logging.getLogger(__name__)


class ChatConsumer(BaseConsumer):

    async def connect(self):
        if not self.user.is_authenticated:
            await self.close(code=4001)
            return
        self.conversation_id = self.scope["url_route"]["kwargs"]["conversation_id"]
        self.group_name      = f"chat_{self.conversation_id}"
        conversation         = await self._get_conversation()
        if not conversation:
            await self.close(code=4003)
            return
        self.conversation = conversation
        await self.channel_layer.group_add(self.group_name, self.channel_name)
        await self.accept()
        await self._mark_delivered_on_connect()
        logger.info("ChatConsumer: user=%s conv=%s", self.user.id, self.conversation_id)

    async def disconnect(self, close_code):
        if hasattr(self, "group_name"):
            await self.channel_layer.group_discard(self.group_name, self.channel_name)

    async def receive(self, text_data=None, bytes_data=None):
        try:
            data     = json.loads(text_data or "{}")
            msg_type = data.get("type", "")
            payload  = data.get("payload", {})
        except json.JSONDecodeError:
            await self.send_error("INVALID_JSON", "Message must be valid JSON.")
            return
        handlers = {
            "send_message":   self._handle_send_message,
            "typing_start":   self._handle_typing_start,
            "typing_stop":    self._handle_typing_stop,
            "mark_read":      self._handle_mark_read,
            "delete_message": self._handle_delete_message,
            "load_history":   self._handle_load_history,
        }
        handler = handlers.get(msg_type)
        if handler:
            await handler(payload)
        else:
            await self.send_error("UNKNOWN_TYPE", f"Unknown event: {msg_type}")

    # ── Client → Server handlers ──────────────────────────────────────────────

    async def _handle_send_message(self, payload):
        content = payload.get("content", "").strip()
        if not content:
            await self.send_error("EMPTY_MESSAGE", "Content cannot be empty.")
            return
        if len(content) > 4000:
            await self.send_error("MESSAGE_TOO_LONG", "Max 4000 chars.")
            return
        message = await self._save_message(content)
        await self.channel_layer.group_send(
            self.group_name,
            {"type": "chat.message_new", "payload": await self._serialize_message(message)},
        )
        await self._enqueue_translation(message)
        await self._send_fcm_if_offline(message)

    async def _handle_typing_start(self, payload):
        await self.channel_layer.group_send(
            self.group_name,
            {"type": "chat.typing_start", "payload": {"user_id": str(self.user.id), "user_name": self.user.name}},
        )

    async def _handle_typing_stop(self, payload):
        await self.channel_layer.group_send(
            self.group_name,
            {"type": "chat.typing_stop", "payload": {"user_id": str(self.user.id)}},
        )

    async def _handle_mark_read(self, payload):
        message_id = payload.get("message_id")
        if message_id and await self._mark_message_read(message_id):
            await self.channel_layer.group_send(
                self.group_name,
                {"type": "chat.read_receipt", "payload": {"message_id": message_id, "read_by": str(self.user.id)}},
            )

    async def _handle_delete_message(self, payload):
        message_id = payload.get("message_id")
        scope      = payload.get("scope", "me")
        if scope not in ("everyone", "me"):
            await self.send_error("INVALID_SCOPE", "scope must be 'everyone' or 'me'.")
            return
        result = await self._delete_message(message_id, scope)
        if result == "not_found":
            await self.send_error("NOT_FOUND", "Message not found.")
        elif result == "window_expired":
            await self.send_error("WINDOW_EXPIRED", f"Can only delete for everyone within {settings.YAAP_MESSAGE_DELETE_WINDOW_HOURS}h.")
        elif result == "not_sender":
            await self.send_error("NOT_SENDER", "Only the sender can delete for everyone.")
        elif result == "ok":
            if scope == "everyone":
                await self.channel_layer.group_send(
                    self.group_name,
                    {"type": "chat.message_deleted", "payload": {"message_id": message_id, "scope": "everyone"}},
                )
            else:
                await self.send_event("chat.message_deleted", {"message_id": message_id, "scope": "me"})

    async def _handle_load_history(self, payload):
        cursor    = payload.get("cursor")
        page_size = min(int(payload.get("page_size", 50)), 100)
        messages, next_cursor = await self._load_history(cursor, page_size)
        await self.send_event("chat.history", {"messages": messages, "next_cursor": next_cursor, "has_more": next_cursor is not None})

    # ── Group → Consumer dispatchers ──────────────────────────────────────────

    async def chat_message_new(self, event):
        await self.send_event("chat.message_new", event["payload"])

    async def chat_typing_start(self, event):
        if event["payload"].get("user_id") != str(self.user.id):
            await self.send_event("chat.typing_start", event["payload"])

    async def chat_typing_stop(self, event):
        if event["payload"].get("user_id") != str(self.user.id):
            await self.send_event("chat.typing_stop", event["payload"])

    async def chat_read_receipt(self, event):
        await self.send_event("chat.read_receipt", event["payload"])

    async def chat_message_deleted(self, event):
        await self.send_event("chat.message_deleted", event["payload"])

    async def chat_message_translated(self, event):
        """
        Deliver the translation only to the user whose language preference matches.
        This event is sent by the Celery translation task after it completes.
        """
        payload = event["payload"]
        if self.user.language_preference == payload.get("language"):
            await self.send_event("chat.message_translated", payload)

    # ── DB helpers ────────────────────────────────────────────────────────────

    @database_sync_to_async
    def _get_conversation(self):
        from apps.messaging.models import Conversation
        from django.db.models import Q
        try:
            return Conversation.objects.get(
                Q(id=self.conversation_id) &
                (Q(participant_a=self.user) | Q(participant_b=self.user))
            )
        except Conversation.DoesNotExist:
            return None

    @database_sync_to_async
    def _save_message(self, content):
        from apps.messaging.models import Message
        msg = Message.objects.create(
            conversation=self.conversation, sender=self.user,
            content=content, original_language=self.user.language_preference,
        )
        self.conversation.last_message = msg
        self.conversation.save(update_fields=["last_message", "updated_at"])
        return msg

    @database_sync_to_async
    def _mark_delivered_on_connect(self):
        from apps.messaging.models import Message
        Message.objects.filter(
            conversation=self.conversation, status=Message.Status.SENT,
        ).exclude(sender=self.user).update(status=Message.Status.DELIVERED)

    @database_sync_to_async
    def _mark_message_read(self, message_id):
        from apps.messaging.models import Message
        return Message.objects.filter(
            id=message_id, conversation=self.conversation,
        ).exclude(sender=self.user).update(status=Message.Status.READ) > 0

    @database_sync_to_async
    def _delete_message(self, message_id, scope):
        from apps.messaging.models import Message
        try:
            msg = Message.objects.get(id=message_id, conversation=self.conversation)
        except Message.DoesNotExist:
            return "not_found"
        if scope == "everyone":
            if msg.sender_id != self.user.id:
                return "not_sender"
            if not msg.can_delete_for_everyone(self.user):
                return "window_expired"
            msg.delete_for_everyone()
        else:
            msg.delete_for_user(self.user)
        return "ok"

    @database_sync_to_async
    def _load_history(self, cursor, page_size):
        from apps.messaging.models import Message
        from django.utils.dateparse import parse_datetime
        qs = Message.objects.visible_to(self.user, self.conversation)
        if cursor:
            try:
                qs = qs.filter(created_at__lt=parse_datetime(cursor))
            except Exception:
                pass
        batch      = list(qs[:page_size + 1])
        has_more   = len(batch) > page_size
        batch      = batch[:page_size]
        next_cursor = batch[-1].created_at.isoformat() if has_more and batch else None
        return [_serialize_msg(m) for m in batch], next_cursor

    @database_sync_to_async
    def _serialize_message(self, message):
        return _serialize_msg(message)

    @database_sync_to_async
    def _enqueue_translation(self, message):
        other = self.conversation.other_participant(self.user)
        if other.language_preference and other.language_preference != message.original_language:
            from services.translation import translate_message_task
            translate_message_task.apply_async(
                args=[str(message.id), other.language_preference], queue="translation"
            )

    @database_sync_to_async
    def _send_fcm_if_offline(self, message):
        other = self.conversation.other_participant(self.user)
        if not other.is_online:
            from apps.friendships.models import UserDevice
            from services.fcm_service import notify_new_message
            tokens = list(UserDevice.objects.filter(user=other).values_list("fcm_token", flat=True))
            if tokens:
                notify_new_message(tokens, self.user.name, message.content[:80], str(self.conversation.id))


def _serialize_msg(m) -> dict:
    return {
        "id": str(m.id), "conversation_id": str(m.conversation_id),
        "sender": {"id": str(m.sender_id), "display_name": getattr(m.sender, "name", ""), "avatar_url": getattr(m.sender, "avatar_url", "")},
        "content": m.content, "original_language": m.original_language,
        "status": m.status, "deleted_for_everyone": m.deleted_for_everyone,
        "created_at": m.created_at.isoformat(), "updated_at": m.updated_at.isoformat(),
    }

"""
Signaling Consumer — Phase 6
Full WebRTC signaling relay between caller and callee.

Connection: ws://host/ws/calls/<room_id>/?token=<jwt>

Client → Server (type field):
  call_offer     { sdp, type:"offer" }
  call_answer    { sdp, type:"answer" }
  ice_candidate  { candidate, sdpMid, sdpMLineIndex }
  call_decline   {}
  call_end       {}
  call_missed    {}

Server → Client:
  signaling.offer        — SDP offer (to callee only)
  signaling.answer       — SDP answer (to caller only)
  signaling.ice          — ICE candidate (to peer only)
  signaling.declined     — call rejected
  signaling.ended        — call ended by peer
  signaling.missed       — no answer timeout
  signaling.peer_joined  — other peer connected
  signaling.peer_left    — other peer disconnected
"""

import json
import logging
from channels.db import database_sync_to_async
from channels_consumers.base_consumer import BaseConsumer

logger = logging.getLogger(__name__)


class SignalingConsumer(BaseConsumer):

    async def connect(self):
        if not self.user.is_authenticated:
            await self.close(code=4001)
            return

        self.room_id    = self.scope["url_route"]["kwargs"]["room_id"]
        self.group_name = f"signaling_{self.room_id}"

        room = await self._get_room()
        if not room:
            await self.close(code=4003)
            return

        self.room = room
        await self.channel_layer.group_add(self.group_name, self.channel_name)
        await self.accept()

        await self.channel_layer.group_send(self.group_name, {
            "type": "signaling.peer_joined",
            "payload": {
                "user_id":      str(self.user.id),
                "display_name": self.user.name,
                "avatar_url":   self.user.avatar_url,
                "language":     self.user.language_preference,
                "role":         "caller" if str(room.caller_id) == str(self.user.id) else "callee",
            },
        })
        logger.info("Signaling connected: user=%s room=%s", self.user.id, self.room_id)

    async def disconnect(self, close_code):
        if not hasattr(self, "group_name"):
            return
        await self.channel_layer.group_send(self.group_name, {
            "type": "signaling.peer_left",
            "payload": {"user_id": str(self.user.id), "close_code": close_code},
        })
        room = await self._reload_room()
        if room and room.is_active:
            await self._end_call_db()
        await self.channel_layer.group_discard(self.group_name, self.channel_name)
        logger.info("Signaling disconnected: user=%s room=%s code=%s", self.user.id, self.room_id, close_code)

    async def receive(self, text_data=None, bytes_data=None):
        try:
            data     = json.loads(text_data or "{}")
            msg_type = data.get("type", "")
            payload  = data.get("payload", {})
        except json.JSONDecodeError:
            await self.send_error("INVALID_JSON", "Invalid JSON.")
            return
        handlers = {
            "call_offer":    self._handle_offer,
            "call_answer":   self._handle_answer,
            "ice_candidate": self._handle_ice,
            "call_decline":  self._handle_decline,
            "call_end":      self._handle_end,
            "call_missed":   self._handle_missed,
        }
        handler = handlers.get(msg_type)
        if handler:
            await handler(payload)
        else:
            await self.send_error("UNKNOWN_TYPE", f"Unknown event: {msg_type}")

    # ── Client → Server handlers ──────────────────────────────────────────────

    async def _handle_offer(self, payload):
        if not await self._is_caller():
            await self.send_error("NOT_CALLER", "Only caller can send offer.")
            return
        if not payload.get("sdp"):
            await self.send_error("MISSING_SDP", "sdp required.")
            return
        await self.channel_layer.group_send(self.group_name, {
            "type": "signaling.offer",
            "payload": {
                "sdp": payload["sdp"], "type": "offer",
                "caller_id": str(self.user.id), "caller_name": self.user.name,
                "caller_lang": self.user.language_preference,
            },
        })

    async def _handle_answer(self, payload):
        if await self._is_caller():
            await self.send_error("NOT_CALLEE", "Only callee can answer.")
            return
        if not payload.get("sdp"):
            await self.send_error("MISSING_SDP", "sdp required.")
            return
        await self._answer_call_db()
        await self.channel_layer.group_send(self.group_name, {
            "type": "signaling.answer",
            "payload": {
                "sdp": payload["sdp"], "type": "answer",
                "callee_id": str(self.user.id), "callee_lang": self.user.language_preference,
            },
        })
        logger.info("Call answered: room=%s", self.room_id)

    async def _handle_ice(self, payload):
        await self.channel_layer.group_send(self.group_name, {
            "type": "signaling.ice",
            "payload": {
                "candidate":     payload.get("candidate"),
                "sdpMid":        payload.get("sdpMid"),
                "sdpMLineIndex": payload.get("sdpMLineIndex"),
                "from_user_id":  str(self.user.id),
            },
        })

    async def _handle_decline(self, payload):
        if await self._is_caller():
            await self.send_error("NOT_CALLEE", "Only callee can decline.")
            return
        await self._decline_call_db()
        await self.channel_layer.group_send(self.group_name, {
            "type": "signaling.declined",
            "payload": {"callee_id": str(self.user.id), "reason": payload.get("reason", "declined")},
        })
        logger.info("Call declined: room=%s", self.room_id)

    async def _handle_end(self, payload):
        await self._end_call_db()
        await self.channel_layer.group_send(self.group_name, {
            "type": "signaling.ended",
            "payload": {"ended_by": str(self.user.id), "ended_by_name": self.user.name},
        })
        logger.info("Call ended: room=%s by=%s", self.room_id, self.user.id)

    async def _handle_missed(self, payload):
        if not await self._is_caller():
            return
        await self._missed_call_db()
        await self.channel_layer.group_send(self.group_name, {
            "type": "signaling.missed",
            "payload": {"room_id": self.room_id},
        })

    # ── Group → Consumer dispatchers ──────────────────────────────────────────

    async def signaling_offer(self, event):
        if not await self._is_caller():          # deliver only to callee
            await self.send_event("signaling.offer", event["payload"])

    async def signaling_answer(self, event):
        if await self._is_caller():              # deliver only to caller
            await self.send_event("signaling.answer", event["payload"])

    async def signaling_ice(self, event):
        if event["payload"].get("from_user_id") != str(self.user.id):
            await self.send_event("signaling.ice", event["payload"])

    async def signaling_declined(self, event):
        await self.send_event("signaling.declined", event["payload"])

    async def signaling_ended(self, event):
        await self.send_event("signaling.ended", event["payload"])

    async def signaling_missed(self, event):
        await self.send_event("signaling.missed", event["payload"])

    async def signaling_peer_joined(self, event):
        if event["payload"].get("user_id") != str(self.user.id):
            await self.send_event("signaling.peer_joined", event["payload"])

    async def signaling_peer_left(self, event):
        if event["payload"].get("user_id") != str(self.user.id):
            await self.send_event("signaling.peer_left", event["payload"])

    # ── DB helpers ────────────────────────────────────────────────────────────

    @database_sync_to_async
    def _get_room(self):
        from apps.calls.models import CallRoom
        try:
            return CallRoom.objects.select_related("caller", "callee").get(room_id=self.room_id)
        except CallRoom.DoesNotExist:
            return None

    @database_sync_to_async
    def _reload_room(self):
        from apps.calls.models import CallRoom
        try:
            return CallRoom.objects.get(room_id=self.room_id)
        except CallRoom.DoesNotExist:
            return None

    @database_sync_to_async
    def _is_caller(self) -> bool:
        if hasattr(self, "room"):
            return str(self.room.caller_id) == str(self.user.id)
        return False

    @database_sync_to_async
    def _answer_call_db(self):
        from apps.calls.models import CallRoom
        try:
            r = CallRoom.objects.get(room_id=self.room_id)
            if r.status == CallRoom.Status.INITIATED:
                r.answer()
        except CallRoom.DoesNotExist:
            pass

    @database_sync_to_async
    def _decline_call_db(self):
        from apps.calls.models import CallRoom
        try:
            r = CallRoom.objects.get(room_id=self.room_id)
            if r.status == CallRoom.Status.INITIATED:
                r.decline()
        except CallRoom.DoesNotExist:
            pass

    @database_sync_to_async
    def _end_call_db(self):
        from apps.calls.models import CallRoom
        try:
            r = CallRoom.objects.get(room_id=self.room_id)
            if r.is_active:
                r.end()
        except CallRoom.DoesNotExist:
            pass

    @database_sync_to_async
    def _missed_call_db(self):
        from apps.calls.models import CallRoom
        try:
            r = CallRoom.objects.get(room_id=self.room_id)
            if r.status == CallRoom.Status.INITIATED:
                r.mark_missed()
        except CallRoom.DoesNotExist:
            pass

import logging
from rest_framework.views import exception_handler
from rest_framework.response import Response
from rest_framework import status

logger = logging.getLogger(__name__)


def custom_exception_handler(exc, context):
    """
    Wraps all DRF exceptions in a consistent envelope:
    {
        "success": false,
        "error": {
            "code": "VALIDATION_ERROR",
            "message": "Human-readable message",
            "details": {...}   # optional field-level errors
        }
    }
    """
    response = exception_handler(exc, context)

    if response is not None:
        error_payload = {
            "success": False,
            "error": {
                "code": _get_error_code(response.status_code),
                "message": _get_message(response.data),
                "details": response.data if isinstance(response.data, dict) else None,
            },
        }
        response.data = error_payload

    else:
        # Unhandled exception — 500
        logger.exception("Unhandled exception in view", exc_info=exc)
        response = Response(
            {
                "success": False,
                "error": {
                    "code": "INTERNAL_ERROR",
                    "message": "An unexpected error occurred. Please try again.",
                    "details": None,
                },
            },
            status=status.HTTP_500_INTERNAL_SERVER_ERROR,
        )

    return response


def _get_error_code(status_code: int) -> str:
    mapping = {
        400: "VALIDATION_ERROR",
        401: "AUTHENTICATION_FAILED",
        403: "PERMISSION_DENIED",
        404: "NOT_FOUND",
        405: "METHOD_NOT_ALLOWED",
        409: "CONFLICT",
        429: "RATE_LIMIT_EXCEEDED",
        500: "INTERNAL_ERROR",
    }
    return mapping.get(status_code, "ERROR")


def _get_message(data) -> str:
    if isinstance(data, dict):
        if "detail" in data:
            return str(data["detail"])
        # Return first field error
        for key, value in data.items():
            if isinstance(value, list) and value:
                return f"{key}: {value[0]}"
            if isinstance(value, str):
                return value
    if isinstance(data, list) and data:
        return str(data[0])
    return "An error occurred."

