// ---- View extensions ----

fun View.show() { visibility = View.VISIBLE }
fun View.hide() { visibility = View.GONE }
fun View.invisible() { visibility = View.INVISIBLE }
fun View.isVisible() = visibility == View.VISIBLE

fun View.showSnackbar(message: String, duration: Int = Snackbar.LENGTH_SHORT) {
    Snackbar.make(this, message, duration).show()
}

fun View.showSnackbarError(message: String) {
    Snackbar.make(this, message, Snackbar.LENGTH_LONG).show()
}

// ---- EditText extensions ----

fun EditText.textFlow(): Flow<String> = callbackFlow {
    val watcher = object : android.text.TextWatcher {
        override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) {}
        override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
            trySend(s.toString())
        }
        override fun afterTextChanged(s: android.text.Editable?) {}
    }
    addTextChangedListener(watcher)
    awaitClose { removeTextChangedListener(watcher) }
}.debounce(Constants.SEARCH_DEBOUNCE_MS)

fun EditText.textString() = text.toString().trim()

// ---- Activity extensions ----

fun Activity.hideKeyboard() {
    val imm = getSystemService(Context.INPUT_METHOD_SERVICE) as InputMethodManager
    imm.hideSoftInputFromWindow(currentFocus?.windowToken, 0)
}

fun Activity.toast(message: String) {
    Toast.makeText(this, message, Toast.LENGTH_SHORT).show()
}

// ---- Fragment extensions ----

fun Fragment.toast(message: String) {
    Toast.makeText(requireContext(), message, Toast.LENGTH_SHORT).show()
}

// ---- ImageView extensions ----

fun ImageView.loadAvatar(url: String?, initials: String = "?") {
    if (url.isNullOrBlank()) {
        // Glide placeholder with initials will be handled by a custom target
        // For simplicity, set a default placeholder drawable
        setImageResource(android.R.drawable.ic_menu_myplaces)
    } else {
        Glide.with(context)
            .load(url)
            .transform(CircleCrop())
            .placeholder(android.R.drawable.ic_menu_myplaces)
            .error(android.R.drawable.ic_menu_myplaces)
            .into(this)
    }
}

fun ImageView.loadRounded(url: String?, cornerRadius: Int = 12) {
    Glide.with(context)
        .load(url)
        .placeholder(android.R.drawable.ic_menu_gallery)
        .error(android.R.drawable.ic_menu_gallery)
        .into(this)
}

// ---- Date/Time extensions ----

fun String.toLocalTime(timezone: String): String {
    return try {
        // Assumes input is UTC ISO8601 datetime
        val tz = TimeZone.getTimeZone(timezone)
        val sdf = SimpleDateFormat("HH:mm", Locale.getDefault()).apply {
            timeZone = tz
        }
        sdf.format(Date()) // Use current time converted to their timezone
    } catch (e: Exception) {
        "--:--"
    }
}

fun getCurrentTimeInTimezone(timezone: String): String {
    return try {
        val tz = TimeZone.getTimeZone(timezone)
        val sdf = SimpleDateFormat("HH:mm", Locale.getDefault()).apply {
            timeZone = tz
        }
        sdf.format(Date())
    } catch (e: Exception) {
        "--:--"
    }
}

fun String.toMessageTimestamp(): String {
    return try {
        val inputSdf = SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss'Z'", Locale.getDefault()).apply {
            timeZone = TimeZone.getTimeZone("UTC")
        }
        val date = inputSdf.parse(this) ?: return this
        val now = Date()
        val diffMs = now.time - date.time
        val diffHours = diffMs / (1000 * 60 * 60)
        when {
            diffHours < 1 -> {
                val diffMins = diffMs / (1000 * 60)
                if (diffMins < 1) "Just now" else "${diffMins}m ago"
            }
            diffHours < 24 -> {
                SimpleDateFormat("HH:mm", Locale.getDefault()).format(date)
            }
            else -> SimpleDateFormat("MMM d", Locale.getDefault()).format(date)
        }
    } catch (e: Exception) {
        this
    }
}

// ---- Intent extras helper ----

inline fun <reified T : Activity> Context.startActivity(vararg extras: Pair<String, Any?>) {
    val intent = Intent(this, T::class.java)
    extras.forEach { (key, value) ->
        when (value) {
            is String -> intent.putExtra(key, value)
            is Int -> intent.putExtra(key, value)
            is Boolean -> intent.putExtra(key, value)
            is Long -> intent.putExtra(key, value)
        }
    }
    startActivity(intent)
}

// ---- Validation extensions ----

fun String.isValidEmail(): Boolean {
    return android.util.Patterns.EMAIL_ADDRESS.matcher(this).matches()
}

fun String.isValidPassword(): Boolean = length >= Constants.MIN_PASSWORD_LENGTH

package com.yaap.app.utils

/**
 * Generic sealed class representing UI state for any async operation.
 * ViewModels emit StateFlow<Result<T>> to the UI layer.
 */
sealed class Result<out T> {
    data class Success<T>(val data: T) : Result<T>()
    data class Error(val message: String, val code: Int? = null) : Result<Nothing>()
    object Loading : Result<Nothing>()
    object Idle : Result<Nothing>()
}

/**
 * Extension to safely map success data.
 */
inline fun <T, R> Result<T>.map(transform: (T) -> R): Result<R> = when (this) {
    is Result.Success -> Result.Success(transform(data))
    is Result.Error -> this
    is Result.Loading -> Result.Loading
    is Result.Idle -> Result.Idle
}

/**
 * Extension to handle success case inline.
 */
inline fun <T> Result<T>.onSuccess(action: (T) -> Unit): Result<T> {
    if (this is Result.Success) action(data)
    return this
}

/**
 * Extension to handle error case inline.
 */
inline fun <T> Result<T>.onError(action: (String, Int?) -> Unit): Result<T> {
    if (this is Result.Error) action(message, code)
    return this
}

package com.yaap.app.utils

import android.content.Context
import android.util.Base64
import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKey
import com.yaap.app.utils.Constants.PREF_ACCESS_TOKEN
import com.yaap.app.utils.Constants.PREF_REFRESH_TOKEN
import dagger.hilt.android.qualifiers.ApplicationContext
import org.json.JSONObject
import javax.inject.Inject
import javax.inject.Singleton

data class JwtClaims(
    val userId: String?,
    val nextStep: String?,
    val email: String?
)

@Singleton
class TokenManager @Inject constructor(
    @ApplicationContext private val context: Context
) {
    private val masterKey = MasterKey.Builder(context)
        .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
        .build()

    private val prefs = EncryptedSharedPreferences.create(
        context,
        "yaap_secure_prefs",
        masterKey,
        EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
        EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
    )

    fun saveTokens(accessToken: String, refreshToken: String) {
        prefs.edit()
            .putString(PREF_ACCESS_TOKEN, accessToken)
            .putString(PREF_REFRESH_TOKEN, refreshToken)
            .apply()
    }

    fun getAccessToken(): String? = prefs.getString(PREF_ACCESS_TOKEN, null)

    fun getRefreshToken(): String? = prefs.getString(PREF_REFRESH_TOKEN, null)

    fun clearTokens() {
        prefs.edit()
            .remove(PREF_ACCESS_TOKEN)
            .remove(PREF_REFRESH_TOKEN)
            .apply()
    }

    fun hasValidToken(): Boolean = getAccessToken() != null

    /**
     * Decode JWT payload (no signature verification — for routing only).
     * Returns null if token is missing or malformed.
     */
    fun decodeJwtClaims(): JwtClaims? {
        val token = getAccessToken() ?: return null
        return try {
            val parts = token.split(".")
            if (parts.size != 3) return null
            val payloadJson = String(Base64.decode(parts[1], Base64.URL_SAFE or Base64.NO_PADDING))
            val json = JSONObject(payloadJson)
            JwtClaims(
                userId = json.optString("user_id").takeIf { it.isNotBlank() },
                nextStep = json.optString("next_step").takeIf { it.isNotBlank() },
                email = json.optString("email").takeIf { it.isNotBlank() }
            )
        } catch (e: Exception) {
            null
        }
    }
}
